#!/usr/bin/env bash
# Deploy the "Advance" modal upgrade to the Vantaca Slack bot on the VPS.
#
# WHAT THIS CHANGES (index.mjs only — the other 3 files are rewritten byte-for-byte
# from the current deployed versions, so this is safe to re-run):
#   - Tapping "Advance ▸" on a morning-briefing card now opens a Slack MODAL
#     instead of posting a confirm message.
#   - The modal opens instantly (loading state), looks the item up LIVE (no write),
#     then shows the concrete plan as two columns: *Current step* and *Moving to*
#     <next step> — so you can SEE exactly where it's going before confirming.
#   - The modal has an editable, optional "Your note" field. Whatever you type is
#     the note written to the step; leave it blank to use the AI-suggested note.
#   - Submit = "Confirm advance" (this click is the approval -> askVantaca(approved)
#     steps the item, re-reads to verify, and reports before/after + note in-thread).
#     Close = "Cancel" (nothing is written).
#
# Backs up all four .mjs (timestamped .bak), writes them, node --check each,
# then `systemctl restart vantaca-slack`.
#
# NOTE: the modal uses views.open/views.update/view_submission. The bot already
# runs in Socket Mode, so no new Slack scopes or interactivity URL are needed.
#
# REQUIREMENTS (not present in the Claude-Code-on-web sandbox):
#   - ssh client + ~/.ssh/vantaca_vps private key, egress to 134.209.126.217:22
#
cd /root/vantaca-mcp/slack-bot && ts=$(date +%s) && for f in index.mjs vantaca-claude.mjs daily-report.mjs digest.mjs; do { [ -f "$f" ] && cp "$f" "$f.bak.$ts"; } || true; done && printf %s "" | base64 -d > index.mjs && printf %s "" | base64 -d > vantaca-claude.mjs && printf %s "" | base64 -d > daily-report.mjs && printf %s "" | base64 -d > digest.mjs && node --check index.mjs && node --check vantaca-claude.mjs && node --check daily-report.mjs && node --check digest.mjs && echo SYNTAX_OK && systemctl restart vantaca-slack && sleep 2 && echo "slack:$(systemctl is-active vantaca-slack)"
